const raw = $input.first().json.output || "";

const clean = raw
  // Fix escaped newlines
  .replace(/\\n/g, '\n')
  // Fix double escaped newlines  
  .replace(/\\\\n/g, '\n')
  // Fix escaped quotes
  .replace(/\\"/g, '"')
  // Fix escaped backslashes
  .replace(/\\\\/g, '')
  // Remove excessive blank lines (3+ newlines → 2)
  .replace(/\n{3,}/g, '\n\n')
  // Clean up spaces before newlines
  .replace(/ +\n/g, '\n')
  // Trim whitespace
  .trim();

return [{ json: { output: clean } }];
